// Time:  O(n^2)
// Space: O(n)

class Solution {
public:
    int numFactoredBinaryTrees(vector<int>& A) {
        static const int M = 1e9 + 7;
        sort(A.begin(), A.end());
        unordered_map<int, int64_t> dp;
        for (int i = 0; i < A.size(); ++i) {
            dp[A[i]] = 1;
            for (int j = 0; j < i; ++j) {
                if (A[i] % A[j] == 0 && dp.count(A[i] / A[j])) {
                   dp[A[i]] = (dp[A[i]] + dp[A[j]] * dp[A[i] / A[j]]) % M;
                }
            }
        }
        return accumulate(dp.cbegin(), dp.cend(), 0L,
                          [](int64_t x, const pair<int, int>& p) {
                              return x + p.second;
                          }) % M;
    }
};

# Time:  O(n^2)
# Space: O(n)


class Solution(object):
    def numFactoredBinaryTrees(self, A):
        """
        :type A: List[int]
        :rtype: int
        """
        M = 10**9 + 7
        A.sort()
        dp = {}
        for i in xrange(len(A)):
            dp[A[i]] = 1
            for j in xrange(i):
                if A[i] % A[j] == 0 and A[i] // A[j] in dp:
                    dp[A[i]] += dp[A[j]] * dp[A[i] // A[j]]
                    dp[A[i]] %= M
        return sum(dp.values()) % M
